/**
 * Shared domain types for the Blast game.
 * Pure TypeScript — zero Cocos dependencies.
 */

// ── Tile colours ──────────────────────────────────────────

export enum TileColor {
    Blue   = 0,
    Red    = 1,
    Green  = 2,
    Yellow = 3,
    Purple = 4,
}

export const TILE_COLOR_COUNT = 5;

// ── Special tile types ────────────────────────────────────

export enum SuperTileType {
    None        = 0,
    RowClear    = 1,   // horizontal rockets  — clears entire row
    ColumnClear = 2,   // vertical rockets    — clears entire column
    RadiusBomb  = 3,   // bomb                — clears R‑radius area
    FieldClear  = 4,   // mega‑bomb           — clears entire field
}

// ── Boosters ──────────────────────────────────────────────

export enum BoosterType {
    None     = 0,
    Bomb     = 1,
    Teleport = 2,
}

// ── Game result ───────────────────────────────────────────

export enum GameResult {
    None = 0,
    Win  = 1,
    Lose = 2,
}

// ── Data structures ───────────────────────────────────────

export interface CellData {
    color: TileColor;
    superType: SuperTileType;
}

export interface GridPosition {
    row: number;
    col: number;
}

// ── Model → View communication DTOs ──────────────────────

export interface GravityMove {
    from: GridPosition;
    to: GridPosition;
    cell: CellData;
}

export interface SpawnedTile {
    position: GridPosition;
    cell: CellData;
    /** How many cells above the grid the tile originates from (for fall animation). */
    fallDistance: number;
}

// ── Helpers ───────────────────────────────────────────────

export function posKey(row: number, col: number): string {
    return `${row},${col}`;
}
